import { createContext, useContext, useState } from 'react';
import { notify } from './notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext(null);

const useNotificationContext = () => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    try {
      await notificationElem.open({
        heading: props.heading,
        subheading: props.subheading,
        type: props.type,
      });
    } catch (error) {
      setError(error);
    }
  };

  return { notify, error };
};

export { NotificationContext, useNotificationContext };
